      /* <flatten type="Javascript"> */
function active$Timesheet$(f) {f.add_onResponseComplete(on$Filter$ResponseComplete);}
function close$Timesheet$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, v = f._language == 'v', s = f.getItemValue('ma_bp'), name = f.getItemValue('ten_bp%l'), d1 = f.getItem('tu_ngay').value, d2 = f.getItem('den_ngay').value, z = f.getItemValue('mau_bc'), id = f.get_id(), h = f.getItem('tu_ngay').field.Label;
      g._dateFrom = f.getItemValue('tu_ngay', null, null, true);
      g._dateTo = f.getItemValue('den_ngay', null, null, true);
      var e1 = (v ? 'Trường <span class="Highlight">' + h + '</span> chưa nhập hoặc giá trị nhập không hợp lệ.' : 'Field <span class="Highlight">' + h + '</span> must not be blank or has invalid value.');
      var diffDate = dateDiffInDays(g._dateFrom, g._dateTo);
      if (diffDate < 0 || diffDate >= 40) {
        $func.hideWait(id);
        $message.show(e1, String.format('$find(\'{0}\').getItem(\'tu_ngay\').focus()', id));
        f._checked = false;
        break;
      }
      g._hiddenForms = [
        {Form: [1], Value: z == '10'},
        {Form: [0], Value: z == '20'}
      ];

      var fieldsHidden = getFieldsHidden(f, diffDate), fieldsShow = getFieldsShow(f, diffDate);
      g._hiddenFields = [{Fields: fieldsHidden, Value: (true)}, {Fields: fieldsShow, Value: (false)}];

      s = s == '' ? (v ? 'tất cả các bộ phận' : 'All Department') : ((v ? 'bộ phận: ' : 'Department: ') + name);
      g._alterTitle = [null, [['%d1', d1, true], ['%d2', d2, true], ['%s', s, true]]];
      g._lengthShow = fieldsShow.split(',').length;
      g._form = f.getItemValue('mau_bc');
      if (g._fields.length > 0) try {init$GridReport$(g);} catch (ex) {}

      var d = ((g._dateFrom.toString())+ (String.fromCharCode(253))+ (g._dateTo.toString()));
      g._keyHidden = ((g._dateFrom.toString())+ (String.fromCharCode(253))+ (g._dateTo.toString())+ (String.fromCharCode(253)) + g._form.toString());
      if (!g._template) g._template = g._form;
      if (!g._day) g._day = d;
      if (!g._v) g._v = g._keyHidden;
      if (g._v != g._keyHidden) {
        var s1 = 'n01,n02,n03,n04,n05,n06,n07,n08,n09,n10,n11,n12,n13,n14,n15,n16,n17,n18,n19,n20,n21,n22,n23,n24,n25,n26,n27,n28,n29,n30,n31,n32,n33,n34,n35,n36,n37,n38,n39,n40';
        var s2 = 'c01,c02,c03,c04,c05,c06,c07,c08,c09,c10,c11,c12,c13,c14,c15,c16,c17,c18,c19,c20';
        var s = '';
        if (g._day != d) s = s1;
        if (g._template != g._form) s = s + (s != '' ? ',' : '') + s2;
        remove$GridReport$Filter(g, s);
        g._v = g._keyHidden, g._day = d, g._template = g._form;
      }
      break;
    default:
      break;
  }
}
function getFieldsHidden(f, n) {
  var v = '';
  for (var i = n + 2; i <= 40; i++) {v += (v == '' ? 'n' : ',n') + (i > 9 ? i : '0' + i);}
  return v;
}
function getFieldsShow(f, n) {
  var v = '';
  for (var i = 1; i <= n + 1; i++) {v += (v == '' ? 'n' : ',n') + (i > 9 ? i : '0' + i);}
  return v;
}
function dateDiffInDays(d1, d2) {
  var u1 = Date.UTC(d1.getFullYear(), d1.getMonth(), d1.getDate()), u2 = Date.UTC(d2.getFullYear(), d2.getMonth(), d2.getDate());
  return Math.floor((u2 - u1) / 86400000);
}

function remove$GridReport$Filter(g, s) {
  var r = (s).split(','), name, field;
  for (i = 0; i < r.length; i++) {
    for (var j = 0; j < g._filter.length; j++) {
      name = $func.trim(r[i]);
      field = $func.findField(name, g._fields)
      if (field) field.FilterPanelValue = '';
      if (g._filter[j].match(/^(\w+):/)[1] == name) {
        Array.removeAt(g._filter, j);
        break;
      }
    }
  }
}/* </flatten> */




